import { css } from '@emotion/core';
import { Typography } from 'components';
import { colors, media, typography } from 'core';
import React, { FC } from 'react';

import { Props } from './props';

const LeftContent: FC<Props> = (props: Props) => {
  return (
    <div
      css={{
        backgroundColor: colors.variants.Brand.Purple,
      }}
      className="tw-p-10 xl:tw-p-14"
    >
      <Typography
        as="h2"
        className="mb-4"
        css={css(
          typography.styles.headingBold22,
          media.queryStyled([
            typography.styles.headingBold22,
            typography.styles.headingBold22,
            typography.styles.headingBold28,
          ]),
        )}
        color={colors.variants.Text.Secondary}
      >
        У Вас есть вопросы о вакцинах от COVID-19. И это хорошо!
      </Typography>
      <Typography
        as="p"
        css={css(
          typography.styles.contentRegular16,
          media.queryStyled([
            typography.styles.contentRegular16,
            typography.styles.contentRegular16,
            typography.styles.contentRegular20,
          ]),
        )}
        color={colors.variants.Text.Secondary}
      >
        Осторожность всегда к месту, когда появляется что-то новое. Осведомленность о вакцинах от
        COVID-19 — важный шаг, который поможет нам остановить эту пандемию. <br />
        Вакцины от COVID-19 бесплатны и стали широко доступны в США. Каждый человек в возрасте от 12
        лет имеет право на вакцинацию от COVID-19.
      </Typography>
    </div>
  );
};

const RightContent: FC = () => {
  return (
    <img
      src="https://www.internationaldisabilityalliance.org/sites/default/files/custom/covid-19-vaccine.jpg"
      alt="Some"
      height="100%"
      css={css`
        width: 100%;
        height: 100%;
        object-fit: cover;
      `}
    />
  );
};

export const VaccineBanner: FC = () => (
  <div
    css={media.query({
      display: ['flex', 'grid'],
      gridTemplateColumns: ['1fr 1fr'],
      flexDirection: ['column-reverse'],
    })}
  >
    <LeftContent></LeftContent>
    <RightContent></RightContent>
  </div>
);
